INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Guided setup wizard$q$, $q$A step-by-step onboarding flow picks a template based on business type and walks new users through core setup instead of an open-ended canvas.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Free hosting and SSL$q$, $q$Every site, including free-tier sites, is hosted by SITE123 with a free SSL certificate included by default.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Built-in online store$q$, $q$Paid plans include ecommerce tools for listing products and accepting payments without a separate platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Mobile-responsive templates$q$, $q$Industry-specific templates automatically adapt layouts for mobile and tablet screens.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Basic SEO tools$q$, $q$Editable meta titles and descriptions plus automatic sitemap generation help pages get indexed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Blog module$q$, $q$A built-in blogging tool lets users publish posts without a separate CMS.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Multilingual site support$q$, $q$SITE123 supports building sites intended for non-English-speaking audiences alongside English.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$24/7 live chat support$q$, $q$Round-the-clock support includes hands-on assistance for users building their first website.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Very easy for absolute beginners to get a site live quickly$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Genuine free-forever plan, not just a time-limited trial$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Affordable entry-level premium pricing versus Wix or Squarespace$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Built-in ecommerce without a separate plugin or platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Responsive 24/7 customer support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Less design flexibility than freeform builders like Webflow or Wix$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$SITE123 branding remains visible on the free plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Fewer advanced features and integrations than larger competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Storage and bandwidth caps persist even on paid tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Smaller third-party app and plugin ecosystem$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Is SITE123 free to use?$q$, $q$Yes, SITE123 offers a free-forever plan with a SITE123 subdomain and limited storage, though a custom domain and full features require a paid Premium plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$What does SITE123 Premium include?$q$, $q$Premium plans add a custom domain connection, more storage and bandwidth, ecommerce functionality, additional email accounts, and removal of SITE123 branding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Does SITE123 support online stores?$q$, $q$Yes, paid plans include a built-in store module for accepting payments and listing products.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Can I connect my own domain to SITE123?$q$, $q$Yes, custom domain connection is available on Premium plans, with domain registration available from roughly $10.80 per month on an annual plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Is SITE123 good for SEO?$q$, $q$SITE123 includes basic SEO tools like editable meta tags and automatic sitemap generation, though it lacks the advanced SEO controls of dedicated SEO platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Does SITE123 offer a refund?$q$, $q$Yes, paid plans come with a 14-day money-back guarantee.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Where is SITE123 based?$q$, $q$SITE123 was founded in 2015 and is headquartered in Beersheba, Israel.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Who is SITE123 best suited for?$q$, $q$SITE123 is aimed at small businesses, freelancers, and individuals who want a simple website without design or coding experience.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Small local business website$q$, $q$A local service business, such as a salon or contractor, launches a simple informational website with contact forms and business hours.$q$, $q$Local small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Personal portfolio or blog$q$, $q$An individual creates a portfolio or blog to showcase work or writing without hiring a developer.$q$, $q$Freelancers and hobbyists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Small online store$q$, $q$A small merchant sets up a basic online store to sell a limited product catalog using the built-in ecommerce module.$q$, $q$Small ecommerce sellers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["SITE123 subdomain","250 MB storage","250 MB bandwidth","Core page editor"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$Premium$q$, $q$From $12.80/month$q$, $q$Billed on long-term annual plan$q$, NULL, $q$["Custom domain connection","Expanded storage and bandwidth","Online store functionality","Email accounts included","SITE123 branding removed"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$overview$q$, $q$SITE123 Overview$q$, 2, ARRAY[$q$SITE123 is a website builder launched in 2015 out of Beersheba, Israel, built specifically for people with no coding or design background. Rather than a blank drag-and-drop canvas, it starts users with an industry-specific template and a guided setup wizard that walks through pages, colors, and content step by step.$q$, $q$The platform targets solo entrepreneurs, local service businesses, and hobbyists who want a working website fast rather than a highly customized one. This trade-off, simplicity over flexibility, is central to how SITE123 differentiates itself from more open-ended builders like Wix or Webflow.$q$, $q$After a decade of operation with no public funding rounds, SITE123 appears to run as a bootstrapped, profitable company with a small team, focused on serving a large volume of small-business customers globally through freemium pricing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$key-features$q$, $q$Key Features of SITE123$q$, 2, ARRAY[$q$Every SITE123 site includes free hosting, a free SSL certificate, and mobile-responsive templates out of the box, so users do not need to configure infrastructure separately. The editor supports blogging, contact forms, and basic image galleries alongside the core page builder.$q$, $q$Paid plans add an online store module with support for accepting payments, letting small businesses sell physical or digital products without a separate ecommerce platform. Basic SEO controls, including editable meta titles, descriptions, and automatic sitemap generation, are built into the editor.$q$, $q$Support is a notable focus for SITE123: the company offers 24/7 live chat and a hands-on website-building assistance service, which is unusual among budget website builders and aimed at users who need extra guidance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', $q$pricing$q$, $q$SITE123 Pricing Plans$q$, 2, ARRAY[$q$SITE123 offers a genuinely free-forever plan that includes a SITE123 subdomain, limited storage and bandwidth, and core editing features, making it possible to build and publish a basic site at no cost.$q$, $q$Paid Premium plans, marketed under names like Basic, Advanced, Professional, and Gold, unlock a custom domain connection, expanded storage and bandwidth, ecommerce functionality, and removal of SITE123 branding. Premium pricing starts at roughly $12.80 per month when paid on a longer-term plan, with shorter commitments costing more per month.$q$, $q$All paid plans come with a 14-day money-back guarantee, letting customers try premium features with limited financial risk before committing long term.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Desktop and cloud crawling$q$, $q$Choose between a local desktop crawler or hosted Sitebulb Cloud infrastructure depending on site size and team needs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Prioritized audit hints$q$, $q$Each detected issue includes a plain-language explanation of its impact and how to fix it.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Visual site crawl maps$q$, $q$Sunburst diagrams and crawl maps visualize site architecture and internal linking structure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$JavaScript rendering support$q$, $q$Crawls can render JavaScript to reflect what modern search engines actually index.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Scheduled recurring audits$q$, $q$Audits can be scheduled to run automatically on a recurring basis to track SEO health over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Analytics and Search Console integration$q$, $q$Connects to Google Analytics and Google Search Console to layer performance data onto crawl findings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$White-label PDF reporting$q$, $q$Agencies can generate branded PDF reports to share technical SEO findings with clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$API access$q$, $q$Higher-tier plans expose an API for automating crawls and pulling data into other systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Beginner-friendly explanations of technical SEO issues$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Detailed, visual site architecture reporting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Flexible desktop or cloud deployment options$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Affordable entry price for freelancers and solo consultants$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Strong reputation among SEO professionals and agencies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Desktop crawls are limited by local machine resources$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Cloud tiers become expensive at high URL volumes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Full feature set has a steeper learning curve than basic crawlers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Smaller integration ecosystem than larger enterprise platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$No fully free tier beyond the trial period$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Is Sitebulb free?$q$, $q$Sitebulb offers a free trial but requires a paid subscription for ongoing use, split between Desktop and Cloud pricing tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$What is the difference between Sitebulb Desktop and Cloud?$q$, $q$Desktop runs crawls locally on the user's machine, while Cloud runs crawls on hosted infrastructure accessible from a browser, better suited for large sites or teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$How many URLs can Sitebulb crawl?$q$, $q$Desktop plans support up to 500,000 URLs per crawl on the Pro tier, while Cloud plans can support audits of up to 10 million URLs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Does Sitebulb render JavaScript?$q$, $q$Yes, Sitebulb can render JavaScript during crawls to reflect how modern search engines see JavaScript-heavy pages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Is Sitebulb suitable for agencies?$q$, $q$Yes, Sitebulb includes white-label PDF reporting and API access, both commonly used by SEO agencies serving multiple clients.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$How does Sitebulb compare to Screaming Frog?$q$, $q$Sitebulb emphasizes prioritized, explained audit hints and visualizations, while Screaming Frog is often used as a raw, highly configurable crawl data tool; many SEOs use both.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Who founded Sitebulb?$q$, $q$Sitebulb was founded in 2017 by Gareth Brown and Patrick Hathaway in the United Kingdom.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Does Sitebulb offer a free trial?$q$, $q$Yes, Sitebulb offers a free trial before requiring a paid Desktop or Cloud subscription.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Freelance SEO consultant auditing client sites$q$, $q$A solo consultant uses Sitebulb Desktop Lite to run technical audits and generate reports for a handful of client websites.$q$, $q$Freelance SEO consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$In-house team running recurring technical audits$q$, $q$A marketing team schedules recurring Sitebulb audits to monitor technical SEO health as the site changes over time.$q$, $q$In-house marketing and SEO teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Agency delivering white-label reports$q$, $q$An SEO agency uses Sitebulb Cloud and white-label PDF reporting to deliver branded audits across multiple client accounts.$q$, $q$SEO and digital marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Desktop Lite$q$, $q$$13.50/month$q$, $q$Billed annually (about $17.50/month billed monthly)$q$, NULL, $q$["10,000 URLs per crawl","5 projects","Desktop app for Windows and Mac"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Desktop Pro$q$, $q$$35/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 500,000 URLs per crawl","Advanced reporting features","Desktop app for Windows and Mac"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Cloud Standard$q$, $q$From $65/month$q$, $q$Monthly$q$, NULL, $q$["Browser-based crawling","Shared team access","Scales with crawl volume"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$Cloud Enterprise$q$, $q$Up to $245/month$q$, $q$Monthly$q$, NULL, $q$["Up to 10 million URLs per audit","Highest crawl volume tier","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$overview$q$, $q$Sitebulb Overview$q$, 2, ARRAY[$q$Sitebulb was founded in 2017 by Gareth Brown and Patrick Hathaway and is based in Biddenden, Kent, United Kingdom. It was built to make technical SEO audits more approachable, pairing raw crawl data with plain-language, prioritized recommendations rather than leaving practitioners to interpret spreadsheets unaided.$q$, $q$The product ships in two forms: Sitebulb Desktop, a native app for Windows and Mac that crawls sites using the user's own machine and bandwidth, and Sitebulb Cloud, a browser-based version that runs crawls on hosted infrastructure for larger sites or teams that need shared access.$q$, $q$Sitebulb remains a small, independently run company with a team of roughly 2 to 10 people, and it has built a strong reputation within the SEO community as a founder-led alternative to larger enterprise crawling platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$key-features$q$, $q$Key Features of Sitebulb$q$, 2, ARRAY[$q$Sitebulb's audits go beyond raw data by attaching a prioritized 'Hint' to each issue found, explaining what it is, why it matters, and how to fix it, which makes the tool accessible to SEOs who are newer to technical auditing.$q$, $q$The tool renders JavaScript during crawls to reflect what modern search engines actually see, and it generates visualizations such as crawl maps and sunburst diagrams to help users understand site architecture and internal linking at a glance.$q$, $q$Sitebulb supports scheduled recurring audits, integrations with Google Analytics and Google Search Console, white-label PDF reporting for agencies, and API access on higher-tier plans for automating audits into other workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('578e0b1c-942b-4b1c-95fa-56e1bee56a20', $q$pricing$q$, $q$Sitebulb Pricing Plans$q$, 2, ARRAY[$q$Sitebulb Desktop is sold in two tiers: Lite, starting around $13.50 per month billed annually with a 10,000 URL crawl limit across five projects, and Pro, around $35 per month, which raises the crawl limit to 500,000 URLs.$q$, $q$Sitebulb Cloud is priced separately from the desktop app and scales with crawl volume, starting around $65 per month and reaching approximately $245 per month for the top tier supporting up to 10 million URLs per audit.$q$, $q$A free trial is available, letting prospective customers test crawl and reporting features before committing to either the desktop or cloud subscription tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Google Cloud infrastructure$q$, $q$Hosting runs on Google Cloud Platform data centers across multiple regions for performance and reliability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Free daily backups$q$, $q$Automatic daily backups are included on all hosting plans at no extra cost.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$SG Optimizer caching plugin$q$, $q$A proprietary WordPress caching and performance plugin built specifically for SiteGround infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Free SSL and CDN$q$, $q$Every plan includes a free SSL certificate and content delivery network.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Staging and Git tools$q$, $q$GrowBig and GoGeek plans include staging environments and Git integration for safer development workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$WordPress.org recommended host$q$, $q$SiteGround is one of a small number of hosts officially recommended by WordPress.org.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$24/7 human support$q$, $q$Live chat, phone, and ticket support are staffed around the clock.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Managed WooCommerce hosting$q$, $q$Optimized hosting configurations specifically tuned for WooCommerce online stores.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Fast, reliable performance on Google Cloud infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Strong reputation for responsive customer support$q$, 1);
