INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Deep WordPress and WooCommerce optimizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Choice of data center regions for global audiences$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Renewal prices are significantly higher than promotional first-term rates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Storage caps are lower than some flat-rate competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$No unlimited storage even on the top shared hosting tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Proprietary Site Tools panel has a learning curve for cPanel veterans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Cloud hosting tier is comparatively expensive versus shared hosting$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Is SiteGround good for WordPress?$q$, $q$Yes, SiteGround is an officially recommended WordPress.org host with built-in optimization tools, staging environments, and automatic updates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$What happens after the SiteGround promotional pricing period ends?$q$, $q$Plans renew at a higher standard rate after the initial promotional term, which is typically the first year or the length of the initial signup period.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Does SiteGround offer a money-back guarantee?$q$, $q$SiteGround offers a refund policy on new hosting signups, though the exact window can vary by plan; check the current terms at signup.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$What is the difference between shared and cloud hosting at SiteGround?$q$, $q$Shared hosting plans share server resources among multiple customers at a lower price, while Cloud Hosting provides dedicated resources for higher-traffic sites at a higher price.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Does SiteGround include a free domain?$q$, $q$SiteGround does not always include a free domain; domain registration or transfer may be a separate cost depending on the current promotion.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Where are SiteGround's data centers located?$q$, $q$SiteGround operates data centers in multiple global regions on Google Cloud Platform, letting customers choose a location closer to their audience.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Does SiteGround help migrate existing websites?$q$, $q$Yes, SiteGround provides free or assisted website migration tools and services depending on the plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$What uptime does SiteGround guarantee?$q$, $q$SiteGround advertises a 99.9 percent uptime commitment backed by service credits, consistent with common industry standards.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Small business launching a first WordPress website$q$, $q$A small business owner uses SiteGround's StartUp plan to launch a WordPress site with minimal technical setup.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Growing ecommerce store on WooCommerce$q$, $q$An online retailer moves to SiteGround's managed WooCommerce hosting for better performance and staging tools as traffic grows.$q$, $q$Ecommerce store owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Developer or agency managing multiple client sites$q$, $q$A developer uses GoGeek's Git integration and staging environments to manage and deploy changes across multiple client websites.$q$, $q$Developers and web agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$StartUp$q$, $q$$2.99/month (promotional)$q$, $q$Promotional first term, renews higher$q$, NULL, $q$["1 website","10 GB storage","Free SSL and CDN","Free daily backups"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$GrowBig$q$, $q$$4.99/month (promotional)$q$, $q$Promotional first term, renews higher$q$, NULL, $q$["Unlimited websites","20 GB storage","Staging tools","Priority support queue"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$GoGeek$q$, $q$$7.99/month (promotional)$q$, $q$Promotional first term, renews higher$q$, NULL, $q$["40 GB storage","Advanced Git integration","Priority support","Higher resource limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$Cloud Hosting$q$, $q$From $100/month$q$, $q$Monthly$q$, NULL, $q$["Dedicated resources on Google Cloud","Scalable CPU and RAM","Advanced management tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$overview$q$, $q$SiteGround Overview$q$, 2, ARRAY[$q$SiteGround was founded in 2004 in Sofia, Bulgaria, by Ivo Tzenov and a group of university friends, and it has grown from a small local hosting provider into one of the best-known independent web hosts globally, now serving millions of domains.$q$, $q$The company is headquartered in Sofia with additional offices in Plovdiv and Stara Zagora, Bulgaria, and Madrid, Spain, and employs an estimated 500 to 1,000 people across shared hosting, cloud infrastructure, and managed WordPress services.$q$, $q$SiteGround runs its hosting infrastructure on Google Cloud Platform data centers in multiple regions, which the company uses to market faster load times and better uptime compared with hosts running on older, non-cloud infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$key-features$q$, $q$Key Features of SiteGround$q$, 2, ARRAY[$q$SiteGround is an officially recommended host on WordPress.org and provides deep WordPress and WooCommerce optimization, including its proprietary SG Optimizer caching plugin, automatic software updates, and staging environments for testing changes safely.$q$, $q$Every plan includes free daily backups, a free SSL certificate, and a free content delivery network, features that many competitors charge extra for or reserve for higher tiers.$q$, $q$Support is delivered 24/7 through live chat, phone, and ticketing with human agents, and SiteGround's proprietary Site Tools dashboard replaces cPanel with a custom, streamlined control panel interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca0329e-c98c-4d5a-847a-38aca9d3e0c4', $q$pricing$q$, $q$SiteGround Pricing Plans$q$, 2, ARRAY[$q$SiteGround's three shared hosting tiers are StartUp, for a single website with 10 GB of storage; GrowBig, which supports unlimited websites, 20 GB of storage, and staging tools; and GoGeek, which adds 40 GB of storage, priority support, and advanced Git integration.$q$, $q$Promotional first-term pricing starts around $2.99 per month for StartUp, $4.99 per month for GrowBig, and $7.99 per month for GoGeek, but renewal pricing after the first billing term increases significantly, a common industry practice worth budgeting for.$q$, $q$Beyond shared hosting, SiteGround offers Managed Cloud Hosting starting around $100 per month for dedicated resources on Google Cloud, aimed at higher-traffic sites and businesses that have outgrown shared hosting.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Figma-to-website import$q$, $q$Directly imports Figma designs and converts them into an editable, publishable website layout.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Real-time multiplayer editing$q$, $q$Multiple teammates can edit the same website project simultaneously on any plan, including free.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Custom domain support$q$, $q$Paid plans let users connect a custom domain to their published site.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Built-in SEO controls$q$, $q$Meta tags and other on-page SEO settings are editable directly within the builder.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Page speed optimization tools$q$, $q$Built-in tools help optimize published sites for faster load times.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Custom font uploads$q$, $q$Users can upload and use custom fonts beyond the built-in font library.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$HTML export$q$, $q$The Pro plan allows exporting clean HTML for use outside the Siter.io platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Unlimited teammates on all plans$q$, $q$Team collaboration is not gated by plan tier, only website and page counts are.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Deep Figma integration built specifically for designers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Real-time collaboration included on every plan, even free$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Generous free plan for small or test projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Affordable entry-level paid tier compared to enterprise design tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Clean HTML export available on the Pro plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Fewer built-in ecommerce features than mainstream builders like Wix$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Smaller template and plugin ecosystem given its newer launch$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Newer product with a smaller established user community$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Advanced features like HTML export are gated to the top plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Public company size and roadmap transparency are limited$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Is Siter.io free to use?$q$, $q$Yes, Siter.io offers a free Start plan with unlimited websites and teammates, though pages and forms are capped and no custom domain is included.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Can I import a Figma file directly into Siter.io?$q$, $q$Yes, Siter.io supports direct Figma import, converting Figma layouts into an editable website structure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Does Siter.io support ecommerce?$q$, $q$Siter.io is primarily a design-focused website builder and does not offer the deep ecommerce features found in dedicated store platforms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$What is included in the Siter.io Pro plan?$q$, $q$The Pro plan costs $24 per month and includes five websites, unlimited pages and forms, and HTML export.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Who built Siter.io?$q$, $q$Siter.io was launched in 2022 by Andrian Valeanu, founder of the New York-based design studio Designmodo.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Can I export my Siter.io site as HTML?$q$, $q$Yes, HTML export is available exclusively on the Pro plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Does Siter.io support custom domains?$q$, $q$Yes, custom domain connection is available starting on the Solo plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Do I need to know how to code to use Siter.io?$q$, $q$No, Siter.io is a no-code tool, though it is built with designers in mind and integrates closely with Figma.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Freelance designer converting Figma mockups into live sites$q$, $q$A freelance designer imports client Figma mockups directly into Siter.io and publishes a live website without developer handoff.$q$, $q$Freelance designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Design agency collaborating in real time$q$, $q$A design team works together in real time within the same Siter.io project to build and refine a client's website.$q$, $q$Design agencies and studios$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Founder with design skills skipping a developer$q$, $q$A startup founder with design experience builds a marketing site directly from a Figma design without hiring a developer.$q$, $q$Startup founders and solo builders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Start$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Unlimited websites","Unlimited teammates","10 pages","3 forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Solo$q$, $q$$7/month$q$, $q$Monthly$q$, NULL, $q$["1 website","Custom domain","10 pages","SEO and page speed tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Plus$q$, $q$$12/month$q$, $q$Monthly$q$, NULL, $q$["3 websites","50 pages","Custom domain","SEO and page speed tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$Pro$q$, $q$$24/month$q$, $q$Monthly$q$, NULL, $q$["5 websites","Unlimited pages and forms","HTML export","Custom domain"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$overview$q$, $q$Siter.io Overview$q$, 2, ARRAY[$q$Siter.io launched in 2022, created by Andrian Valeanu, founder of the New York-based design studio Designmodo. It was built to give designers a way to turn existing design work into live websites without needing a developer or writing code.$q$, $q$Unlike general-purpose website builders aimed at small businesses, Siter.io is positioned toward designers and design-led teams who already work in tools like Figma and want a direct path from design file to published site.$q$, $q$The product combines a visual, layer-based editor with real-time multiplayer collaboration, letting multiple team members work on the same website project simultaneously, similar to how design teams already collaborate in Figma.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$key-features$q$, $q$Key Features of Siter.io$q$, 2, ARRAY[$q$The standout feature is direct Figma import, which converts existing Figma frames and layouts into an editable, publishable website structure, saving designers from rebuilding a design from scratch in a separate tool.$q$, $q$Real-time collaboration is available on every plan, including the free tier, and lets unlimited teammates work within the same account regardless of plan level, with website count and page limits being the main constraints that scale with price.$q$, $q$Paid plans add custom domain connection, built-in SEO controls, page-speed optimization tools, and custom font uploads, and the top Pro plan adds clean HTML export for developers who want to take the generated code elsewhere.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', $q$pricing$q$, $q$Siter.io Pricing Plans$q$, 2, ARRAY[$q$The free Start plan supports unlimited websites and unlimited teammates but is capped at 10 pages and 3 forms per project, and does not include a custom domain, making it best suited for testing or very small sites.$q$, $q$The Solo plan costs $7 per month for one website with a custom domain and 10 pages, while the Plus plan costs $12 per month and raises the limit to three websites and 50 pages, adding room for small agencies managing a handful of client sites.$q$, $q$The Pro plan costs $24 per month, supports five websites with unlimited pages and forms, and is the only tier that includes HTML export, letting teams hand off a finished export to a development workflow if needed.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca133bfb-1107-4109-8688-45beef7d4d03', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Block-level bidirectional linking$q$, $q$Every block has a unique ID that can be referenced or transcluded anywhere else in a user's notes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Local-first Markdown and JSON storage$q$, $q$Notes are stored locally in a readable Markdown plus JSON format rather than a proprietary database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Optional encrypted cloud sync$q$, $q$An official paid cloud sync service is available for users who do not want to configure third-party sync.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Cross-platform apps$q$, $q$Native apps are available for Windows, macOS, Linux, Android, and iOS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Graph view$q$, $q$Visualizes connections between notes and blocks as an interactive network.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Web clipper extension$q$, $q$A browser extension captures web content directly into SiYuan notebooks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Plugin and theme support$q$, $q$The app supports community plugins and themes to extend functionality and appearance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Self-hosting supported$q$, $q$Users can self-host sync using WebDAV, S3-compatible storage, or Resilio Sync instead of a paid cloud service.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Fully free and open source core application$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Strong data ownership with local Markdown and JSON storage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Active open-source community with over 45,000 GitHub stars$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Works fully offline with no forced cloud dependency$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Flexible self-hosted sync options via WebDAV or S3$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Community and some documentation lean toward Chinese-language users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Steeper learning curve than mainstream consumer note apps$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Smaller plugin ecosystem than more established tools like Obsidian$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Official cloud sync requires a paid PRO purchase or subscription$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Company backing and long-term roadmap are less publicly documented than VC-backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Is SiYuan really free?$q$, $q$Yes, the core application with block editing, Markdown support, and offline access is free for both personal and commercial use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Is SiYuan open source?$q$, $q$Yes, SiYuan is fully open source and released under the AGPL-3.0 license with its code public on GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Does SiYuan work offline?$q$, $q$Yes, SiYuan is offline-first and stores all notes locally by default.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$What is a block reference in SiYuan?$q$, $q$A block reference lets any paragraph, heading, or list item be linked to or embedded in another location in a user's notes, enabling bidirectional linking.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Can I self-host sync for SiYuan?$q$, $q$Yes, users can sync notes using third-party services like WebDAV, S3-compatible storage, or Resilio Sync instead of paying for official cloud sync.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Is SiYuan available in English?$q$, $q$Yes, SiYuan supports an English interface alongside Chinese and other languages.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Is my data private with SiYuan?$q$, $q$SiYuan stores data locally by default and offers optional encrypted cloud sync, giving users control over where their data lives.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$How does SiYuan compare to Obsidian or Notion?$q$, $q$Like Obsidian, SiYuan is local-first and privacy-focused, but it uses native block-level references similar to Notion rather than page-only linking.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Personal knowledge base with linked notes$q$, $q$An individual builds a personal knowledge base using block references and bidirectional links to connect related ideas over time.$q$, $q$Knowledge workers and lifelong learners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Privacy-conscious self-hosted note sync$q$, $q$A privacy-conscious user syncs notes across devices using self-hosted WebDAV or S3 storage instead of a proprietary cloud service.$q$, $q$Privacy-focused individuals and technical users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Research organization with block-level references$q$, $q$A researcher organizes findings and references at the block level across many interconnected documents.$q$, $q$Researchers and academics$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Free$q$, $q$$0$q$, $q$Lifetime$q$, NULL, $q$["Full block editing","Markdown support","Offline access","Local storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$PRO Features$q$, $q$$64 one-time (discounted from $96)$q$, $q$One-time, lifetime access$q$, NULL, $q$["Third-party S3 sync integration","Third-party WebDAV sync integration","All free features included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$Subscription$q$, $q$$148/year (discounted from $296)$q$, $q$Annual subscription$q$, NULL, $q$["Official cloud asset hosting","8GB official cloud storage","Cloud inbox","Official data sync and backup"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$overview$q$, $q$SiYuan Overview$q$, 2, ARRAY[$q$SiYuan is an open-source personal knowledge management application developed by the B3log team, a group that has been building open source software since 2009 and working full-time on open source projects since 2018. The app is released under the AGPL-3.0 license with its full source code public on GitHub.$q$, $q$The core philosophy behind SiYuan is privacy and data ownership: notes are stored locally as Markdown files paired with JSON metadata, meaning users can read and move their data without relying on a proprietary format or a mandatory cloud account.$q$, $q$SiYuan has attracted a large and active open-source community, with its GitHub repository surpassing 45,000 stars, and it ships as native desktop apps for Windows, macOS, and Linux plus mobile apps for Android and iOS.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$key-features$q$, $q$Key Features of SiYuan$q$, 2, ARRAY[$q$At the core of SiYuan is block-level referencing: every piece of content, whether a paragraph, heading, or list item, is a discrete block with a unique ID that can be linked or embedded anywhere else in a user's notes, enabling true bidirectional linking rather than simple page-to-page links.$q$, $q$A graph view visualizes the connections between blocks and documents, helping users see how their notes relate to one another as a network rather than a flat folder structure, a workflow similar to Obsidian's graph view.$q$, $q$Because sync is not tied to a mandatory proprietary server, users can sync their notes using third-party services like WebDAV, S3-compatible storage, or Resilio Sync, or opt into SiYuan's own official cloud sync service for convenience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', $q$pricing$q$, $q$SiYuan Pricing Plans$q$, 2, ARRAY[$q$The core SiYuan application is free for both personal and commercial use, on a lifetime basis, and includes the full block-editing, Markdown, and offline feature set with no artificial limits on note count or local usage.$q$, $q$A one-time PRO purchase, priced around $64 (discounted from $96), unlocks integration with third-party sync and backup services such as Amazon S3 and WebDAV, useful for users who want automated sync without relying on SiYuan's own cloud.$q$, $q$A recurring Subscription plan, priced around $148 per year (discounted from $296), adds SiYuan's official cloud sync service, 8GB of official cloud storage, cloud asset hosting, and a cloud inbox for users who prefer a fully managed sync experience.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fc868bfd-fdf4-4187-9d7e-b719006af946', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
