INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Advanced analytics with exports$q$, $q$Reporting includes exportable data, useful for agencies delivering client reports.$q$, 4);
