INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Social listening$q$, $q$Tracks brand mentions and relevant conversations across connected platforms.$q$, 6);
