INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$What platforms does Sked Social support?$q$, $q$Sked Social supports Instagram, TikTok, Facebook, LinkedIn, Pinterest, YouTube, and Google Business Profile, among others.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Does Sked Social offer a free trial?$q$, $q$Yes, every plan includes a 14-day free trial with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$What is the difference between the Grow and Accelerate plans?$q$, $q$Grow includes 3 users and 6 profiles with approval workflows as paid add-ons, while Accelerate includes 6 users, 10 profiles, and approvals plus advanced analytics by default.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Does Sked Social support client approvals?$q$, $q$Yes, Sked Social offers customizable internal and external approval portals, a key feature for agencies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Is there a free plan for Sked Social?$q$, $q$No, Sked Social does not offer an ongoing free plan, but it does offer a 14-day free trial.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Can I add extra social profiles to my Sked Social plan?$q$, $q$Yes, additional profiles can be added to Grow and Accelerate plans for an extra annual fee per profile.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Is Sked Social good for agencies?$q$, $q$Yes, Sked Social is widely used by agencies due to its client approval portals, white-label reporting, and multi-brand management tools.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Where is Sked Social headquartered?$q$, $q$Sked Social was founded in 2013 and is headquartered in Melbourne, Victoria, Australia.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Agency managing approvals across client brands$q$, $q$A marketing agency uses Sked Social's approval workflows to route content through internal and client review before publishing across several brand accounts.$q$, $q$Marketing and social media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Solo social media manager scheduling for one brand$q$, $q$An individual social media manager uses the Basic plan to schedule and publish content for a single brand across multiple platforms.$q$, $q$Solo social media managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Multi-location business coordinating local profiles$q$, $q$A multi-location business uses Sked Social to coordinate Google Business Profile updates and social posts across many local accounts.$q$, $q$Multi-location and franchise businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Basic$q$, $q$$24/month$q$, $q$Billed annually at $290/year$q$, NULL, $q$["1 user","1 profile per platform","Scheduling to every channel","Brand-trained AI captions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Grow$q$, $q$$58/month$q$, $q$Billed annually at $690/year$q$, NULL, $q$["3 users","6 profiles","Profile-level permissions","Approval workflow add-ons available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Accelerate$q$, $q$$166/month$q$, $q$Billed annually at $1,990/year$q$, NULL, $q$["6 users","10 profiles","Approvals included","Advanced analytics with exports"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$Custom$q$, $q$From $249/month$q$, $q$Custom$q$, NULL, $q$["Enterprise access controls","Dedicated account management","Tailored workflows","Compliance support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$overview$q$, $q$Sked Social Overview$q$, 2, ARRAY[$q$Sked Social was founded in 2013 and is headquartered in Melbourne, Victoria, Australia. It has grown into a social media scheduling platform used by solo social media managers up through agencies managing many client brands at once.$q$, $q$The platform supports scheduling and publishing across major channels including Instagram, TikTok, Facebook, LinkedIn, Pinterest, YouTube, and Google Business Profile, positioning it as a broad, multi-channel scheduler rather than a single-platform tool.$q$, $q$Sked Social operates with a lean team, publicly estimated at roughly 11 to 50 employees spread across multiple continents, while reporting over $10 million in annual revenue and serving a customer base in the range of 10,000 businesses.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$key-features$q$, $q$Key Features of Sked Social$q$, 2, ARRAY[$q$Sked Social is particularly known for agency-oriented workflow tools, including customizable client approval portals and a review process that lets external stakeholders approve content without needing a full account login.$q$, $q$A unified social inbox consolidates messages and comments from connected platforms into one place, while brand-trained AI helps generate on-brand captions faster than writing each post manually.$q$, $q$The platform also includes visual content calendars, social listening features, advanced analytics with exportable reports, and native mobile apps for iOS and Android so teams can manage content on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4d365b4-e7ab-418b-af7c-34a65c4165e9', $q$pricing$q$, $q$Sked Social Pricing Plans$q$, 2, ARRAY[$q$The Basic plan costs $24 per month, billed annually at $290 per year, and includes one user and one profile per connected platform, making it suited to a single social media manager handling one brand.$q$, $q$The Grow plan costs $58 per month, billed annually at $690 per year, and expands to 3 users and 6 profiles, with internal and external approval workflows available as paid add-ons for teams that need review steps.$q$, $q$The Accelerate plan costs $166 per month, billed annually at $1,990 per year, and includes approvals and advanced analytics by default for 6 users and 10 profiles, while a Custom plan starting from $249 per month covers enterprise needs like dedicated account management and tailored access controls.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Native macOS vector editor$q$, $q$A purpose-built, vector-first design app native to Mac, optimized for interface design work.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Reusable symbols and shared libraries$q$, $q$Design components can be reused and kept consistent across files through shared libraries.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Real-time multiplayer collaboration$q$, $q$Multiple designers can edit the same document simultaneously on subscription plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Developer handoff tools$q$, $q$Engineers can inspect exact specs, colors, and export assets directly from design files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Version history$q$, $q$Past states of a document are preserved and can be restored.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Web app and mobile companion apps$q$, $q$Designs can be viewed and reviewed via a browser-based app and iPhone or iPad companion apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Plugin ecosystem$q$, $q$A wide range of third-party plugins extend Sketch's default functionality.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Prototyping tools$q$, $q$Built-in prototyping lets designers link artboards together to simulate user flows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Mature, polished native Mac performance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Strong plugin and shared library ecosystem$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Flexible one-time license option for freelancers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Solid developer handoff tooling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Long track record in the UI/UX design industry since 2010$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Native app is Mac-only, unlike fully cross-platform competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Lost significant market share to Figma's browser-based collaboration model$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Per-editor pricing adds up for larger design teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Real-time collaboration only available on subscription plans, not the one-time license$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Enterprise-level features cost significantly more than the base plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Is Sketch only available for Mac?$q$, $q$The native Sketch app is Mac-only, though a web app and mobile companion apps are also available for viewing and light editing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Can I try Sketch for free?$q$, $q$Sketch subscription plans include a 30-day free trial; the one-time Mac-only license does not include a free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$What is the difference between the Mac-only license and a subscription?$q$, $q$The Mac-only license is a one-time $120 purchase for the native app without collaboration features, while subscriptions add real-time collaboration, the web app, and ongoing updates.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Does Sketch support real-time collaboration?$q$, $q$Yes, real-time multiplayer collaboration is available on all subscription plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$How does Sketch compare to Figma?$q$, $q$Sketch is a native Mac app with an optional web component, while Figma is fully browser-based; Figma has become more dominant for real-time team collaboration, while Sketch retains a following for native Mac performance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Does Sketch offer a web app?$q$, $q$Yes, Sketch includes a browser-based web app alongside its native macOS application.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$What is included in the Sketch Professional plan?$q$, $q$Professional costs $24 per editor per month and adds single sign-on, project archiving, and permission groups on top of the Standard plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Can teams use single sign-on with Sketch?$q$, $q$Yes, single sign-on is available starting on the Professional plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$UI/UX designer building app interfaces natively on Mac$q$, $q$A product designer uses Sketch's native macOS app to design and prototype mobile and web interfaces.$q$, $q$UI/UX designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Design team collaborating on a shared design system$q$, $q$A design team uses shared libraries and real-time collaboration to maintain a consistent design system across many projects.$q$, $q$Product design teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Freelance designer preferring a one-time license$q$, $q$A freelance designer purchases the one-time Mac-only license instead of a recurring subscription for occasional project work.$q$, $q$Freelance and independent designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Standard$q$, $q$$12/editor/month$q$, $q$Billed annually$q$, NULL, $q$["Real-time collaboration","Unlimited documents","Unlimited free viewers","Version history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Professional$q$, $q$$24/editor/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Standard","Single sign-on","Project archiving","Permission groups"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Enterprise$q$, $q$$44/editor/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Professional","SCIM provisioning","Bring-your-own-key encryption","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$Mac-only License$q$, $q$$120 one-time$q$, $q$One-time purchase, 1 year of updates included$q$, NULL, $q$["Native Mac app","Offline design and prototyping","No collaboration features","No free trial"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$overview$q$, $q$Sketch Overview$q$, 2, ARRAY[$q$Sketch was created in 2010 by Pieter Omvlee and a small team originally operating under the name Bohemian Coding in the Netherlands. The product and company are today known as Sketch B.V.$q$, $q$Sketch is widely credited as one of the tools that shifted mainstream interface design away from raster tools like Photoshop toward a dedicated, vector-first design workflow, introducing concepts such as reusable symbols that influenced how the entire UI design tool category evolved.$q$, $q$The application remains a native macOS app at its core, supplemented over time by a browser-based web app and mobile companion apps, as the company adapted to competition from fully browser-based tools like Figma.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$key-features$q$, $q$Key Features of Sketch$q$, 2, ARRAY[$q$Sketch's editor is built around reusable symbols and shared libraries, letting design teams maintain consistent components, such as buttons or icons, across many files from a single source of truth.$q$, $q$Real-time multiplayer collaboration lets multiple designers work in the same document simultaneously, with version history preserving past states of a file for easy rollback.$q$, $q$Developer handoff tools let engineers inspect exact spacing, colors, and assets directly from a design file, and Sketch supports a broad plugin ecosystem that extends the editor with third-party functionality.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c10185e-f762-462e-9a99-b6b50263b7cf', $q$pricing$q$, $q$Sketch Pricing Plans$q$, 2, ARRAY[$q$The Standard plan costs $12 per editor per month when billed annually and includes real-time collaboration, unlimited documents, and unlimited free viewers, making it the entry point for small teams.$q$, $q$The Professional plan costs $24 per editor per month and adds single sign-on, project archiving, and permission groups, while Enterprise costs $44 per editor per month and adds SCIM provisioning and bring-your-own-key encryption for larger organizations with stricter security needs.$q$, $q$For designers who prefer not to subscribe, Sketch still sells a one-time Mac-only license for $120 per seat, which includes one year of updates but excludes collaboration features, online sharing, and the mobile preview app.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$30,000+ on-demand video classes$q$, $q$A large, constantly updated catalog spans creative, business, and productivity topics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Project-based learning$q$, $q$Most classes are built around a hands-on project rather than passive video watching.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Offline viewing in mobile app$q$, $q$Classes can be downloaded for offline viewing on the Skillshare mobile app.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Curated learning paths$q$, $q$Related classes are grouped into paths aimed at a broader skill or career goal.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Creator-led original content$q$, $q$Instructors are working creative professionals rather than accredited academic instructors.$q$, 4);
