INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Is Skillshare free?$q$, $q$A limited selection of classes is free, but full catalog access requires a paid Premium Membership.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$How much does Skillshare Premium cost?$q$, $q$Premium Membership costs $167.88 per year, equivalent to $13.99 per month when billed annually; month-to-month billing costs more.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Does Skillshare offer certificates?$q$, $q$Skillshare does not offer accredited certificates or degrees; it focuses on practical, project-based skill-building instead.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$What is Skillshare for Teams?$q$, $q$Skillshare for Teams is a business plan that gives employees Premium access, priced at $159 per user per year, billed annually.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Can I cancel my Skillshare subscription anytime?$q$, $q$Yes, Premium Membership can generally be canceled at any time, though refund policies depend on the current terms at signup.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Does Skillshare offer a free trial?$q$, $q$Yes, new members typically receive a free trial period before Premium Membership billing begins.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$What subjects does Skillshare cover?$q$, $q$Skillshare focuses on creative and entrepreneurial skills including illustration, design, photography, video, writing, marketing, and productivity.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Is Skillshare good for professional certification?$q$, $q$No, Skillshare is better suited for practical creative skill-building than for accredited professional certification, unlike platforms such as Coursera.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Creative freelancer building practical design skills$q$, $q$A freelance illustrator or designer takes project-based classes to learn new techniques and build a portfolio piece.$q$, $q$Creative freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Small business owner learning marketing skills$q$, $q$A small business owner takes marketing and productivity classes to build in-house skills instead of hiring an agency.$q$, $q$Small business owners and entrepreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Company offering Skillshare as an employee benefit$q$, $q$An employer provides Skillshare for Teams access as an ongoing creative and professional-development benefit for staff.$q$, $q$HR and learning and development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Access to a limited selection of classes","No offline downloads","No full catalog access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Premium Membership (Annual)$q$, $q$$13.99/month ($167.88/year)$q$, $q$Billed annually$q$, NULL, $q$["Full class catalog access","Offline downloads","Class project feedback","Free trial for new members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Premium Membership (Monthly)$q$, $q$$17.99-$32/month$q$, $q$Billed monthly$q$, NULL, $q$["Full class catalog access","No annual commitment","Offline downloads"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Skillshare for Teams$q$, $q$$159/user/year$q$, $q$Billed annually only$q$, NULL, $q$["Premium access for all employees","Team usage analytics","Curated learning paths for teams"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$overview$q$, $q$Skillshare Overview$q$, 2, ARRAY[$q$Skillshare was founded by Michael Karnjanaprakorn and Malcolm Ong in New York City in November 2010, with the platform publicly launching to users in 2011. The company remains headquartered in New York.$q$, $q$The platform built its identity around creative and entrepreneurial skills rather than accredited academic or technical certification, positioning itself as a community of practitioners teaching practical, project-based classes.$q$, $q$Skillshare today employs an estimated 500 to 700 people and offers a catalog of more than 30,000 classes, spanning design, illustration, photography, video, writing, marketing, and productivity topics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$key-features$q$, $q$Key Features of Skillshare$q$, 2, ARRAY[$q$Most Skillshare classes are structured around a hands-on class project, encouraging students to apply what they learn immediately and share their work for feedback from other students, rather than passively watching lectures.$q$, $q$Instructors are typically working creative professionals rather than credentialed academics, which gives the catalog a practical, industry-current feel, though it also means class quality can vary more than on accreditation-focused platforms.$q$, $q$The mobile app supports offline downloads for learning without an internet connection, and Skillshare curates learning paths that group related classes together around a broader skill or career goal.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$pricing$q$, $q$Skillshare Pricing Plans$q$, 2, ARRAY[$q$A limited selection of classes is available for free without a subscription, but full catalog access requires a Premium Membership.$q$, $q$Premium Membership costs $167.88 per year, equivalent to $13.99 per month when billed annually, while paying strictly month-to-month costs more, typically between $17.99 and $32 per month depending on the current offer.$q$, $q$Skillshare for Teams extends premium access to organizations at $159 per user per year, billed annually only, aimed at companies offering Skillshare as an employee learning and development benefit.$q$]::text[], 2);
