-- Enrichment marathon batch: SITE123, Sitebulb, SiteGround, Siter.io, SiYuan, Sked Social, Sketch, Skillshare

-- ── SITE123 ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SITE123 is a beginner-friendly, all-in-one website builder that lets small businesses and individuals create a professional website, online store, or blog without writing code.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$$12.80/month (billed on a long-term annual plan)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Beersheba, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SITE123 Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$SITE123 is an Israeli no-code website builder for small businesses. See 2026 pricing, features, pros and cons, and how it compares to competitors.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SITE123 is a cloud-based, no-code website builder founded in 2015 and headquartered in Beersheba, Israel. The platform is designed for small business owners, freelancers, and individuals who have no design or coding experience and want to launch a website quickly. Users pick a template based on their business category, such as restaurant, portfolio, online store, or blog, and then customize it through a simplified guided editor rather than a fully freeform canvas, which keeps the learning curve low compared with builders like Wix or Squarespace. SITE123 includes a free-forever plan with a SITE123 subdomain and limited storage, plus paid Premium tiers, referred to as Basic, Advanced, Professional, and Gold, that unlock a custom domain, additional storage and bandwidth, ecommerce functionality, email accounts, and removal of SITE123 branding. Premium pricing starts around $12.80 per month when billed on a long-term plan, with a 14-day money-back guarantee on paid plans. Built-in features include basic SEO tools such as meta tags and sitemap generation, mobile-responsive design, a blogging module, an online store with payment gateway support, contact forms, and 24/7 customer support with website-building assistance. SITE123 operates with a small team of roughly 11-50 employees and has grown for a decade without taking on public venture funding, suggesting a bootstrapped, profitable operating model. It positions itself against Wix, GoDaddy Website Builder, and Weebly as a lower-cost, simplicity-first alternative for beginners.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8ab99a23-e2f0-4b0d-b603-9ded27a0f2c6';

