-- ── Sitebulb ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sitebulb is a desktop and cloud technical SEO auditing and website crawling tool built in the UK, used by SEO professionals and agencies to find and prioritize site issues.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (desktop license tiers plus cloud crawl tiers)$q$, pricing_model),
  starting_price = COALESCE($q$$13.50/month (billed annually, Desktop Lite)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$2-10 employees$q$, company_size),
  headquarters = COALESCE($q$Biddenden, Kent, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sitebulb Review 2026: Pricing, Features and How It Compares$q$, seo_title),
  seo_meta_description = COALESCE($q$Sitebulb is a UK-built desktop and cloud SEO crawler. Compare 2026 pricing, features, pros and cons for this technical SEO auditing tool.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sitebulb is a technical SEO auditing and website crawling tool founded in 2017 by Gareth Brown and Patrick Hathaway, and headquartered in Biddenden, Kent, in the United Kingdom. It is built specifically for SEO professionals, consultants, and agencies who need to audit websites for crawlability, indexability, on-page, and technical SEO issues. Unlike some enterprise-only crawlers, Sitebulb ships as a desktop application for Windows and Mac, called Sitebulb Desktop, as well as a browser-based Sitebulb Cloud product, giving users the choice between running audits locally or offloading large crawls to hosted infrastructure. The desktop Lite plan starts at roughly $13.50 per month when billed annually, about $17.50 month-to-month, and supports up to 10,000 URLs per crawl across five projects, while the Pro plan costs around $35 per month and raises the crawl limit to 500,000 URLs. Sitebulb Cloud plans range from roughly $65 to $245 per month depending on crawl volume, with the largest cloud tier supporting audits of up to 10 million URLs. The product is known in the SEO community for its visual, prioritized audit reports that explain issues in plain language with actionable hints, its site-wide visualizations such as crawl maps and sunburst diagrams, and its Google Data Studio and API integrations. Sitebulb remains a small, privately held UK company with a team of roughly 2 to 10 employees, positioning it as a founder-led alternative to larger crawlers like Screaming Frog, DeepCrawl, and Botify.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '578e0b1c-942b-4b1c-95fa-56e1bee56a20';

