-- ── Siter.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Siter.io is a collaborative, no-code website builder built for designers, letting teams import Figma designs and turn them into live, responsive websites.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$$7/month (Solo plan)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, NY, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Siter.io Review 2026: Pricing and Features for Designers$q$, seo_title),
  seo_meta_description = COALESCE($q$Siter.io is a no-code website builder for designers with Figma import and real-time collaboration. See 2026 pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Siter.io is a cloud-based, no-code website builder launched in 2022 by Andrian Valeanu, the founder of Designmodo, a New York-based digital product studio that also built the tool. Siter.io is aimed specifically at designers and design-led teams rather than general small-business owners, differentiating itself from builders like Wix or SITE123 by supporting direct import of Figma designs, which it converts into responsive, publishable websites without requiring the user to write code. The editor combines a visual, layer-based canvas with real-time multiplayer collaboration, letting multiple teammates edit the same project simultaneously, similar to Figma's own collaboration model. Siter.io offers a free Start plan with unlimited websites and teammates but capped at 10 pages and 3 forms, and paid tiers named Solo at $7 per month for one website, Plus at $12 per month for three websites and 50 pages, and Pro at $24 per month for five websites with unlimited pages and forms plus HTML export. All paid plans include hosting, SSL certificates, custom domains, SEO controls, page-speed optimization, and custom fonts. Because Siter.io exports clean HTML on its top tier, agencies and freelance designers can use it to prototype and ship client sites without handing off to a developer for basic builds. As a newer entrant, detailed company size and funding figures are not publicly disclosed, but it operates under the Designmodo umbrella, which has built design tools and marketplaces since the 2010s.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ca133bfb-1107-4109-8688-45beef7d4d03';

