-- ── SiYuan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SiYuan is a free, open-source, privacy-first personal knowledge management app that combines block-based editing, Markdown, and bidirectional linking, similar to Notion or Obsidian.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source, with optional paid PRO features and cloud subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (core app); PRO features from $64 one-time$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$SiYuan Review 2026: Free Open-Source Note-Taking App$q$, seo_title),
  seo_meta_description = COALESCE($q$SiYuan is a free, open-source, privacy-first personal knowledge management app with block references and bidirectional links. See 2026 features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SiYuan is a free, open-source, privacy-first personal knowledge management application developed by the team behind B3log, a long-running open source community whose creators have described themselves as full-time open source developers since 2018. SiYuan is self-hostable and offline-first: notes are stored locally in a human-readable format that mixes Markdown files with JSON metadata, so users retain full ownership and portability of their data rather than being locked into a proprietary cloud database. The application is released under the AGPL-3.0 license, with its source code publicly hosted on GitHub, where the project has accumulated more than 45,000 stars, reflecting a substantial and active open-source community. Functionally, SiYuan sits alongside tools like Notion, Obsidian, and Logseq: every paragraph, list item, or heading is a discrete block with its own unique ID, which can be referenced or transcluded anywhere else in a user's notebook, enabling bidirectional linking and a network-style graph view of ideas rather than a flat folder hierarchy. Core editing, block references, Markdown support, and offline access are free for both personal and commercial use, on a lifetime basis. Paid tiers exist for convenience features rather than core functionality: a one-time PRO purchase around $64, discounted from $96, unlocks third-party S3 and WebDAV sync and backup integration, while a subscription around $148 per year, discounted from $296, adds official cloud asset hosting, 8GB of official cloud storage, and a cloud inbox. SiYuan ships native apps for Windows, macOS, and Linux, plus mobile apps for Android and iOS, and a browser extension for web clipping.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fc868bfd-fdf4-4187-9d7e-b719006af946';

