-- ── Sked Social ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sked Social is an Australian social media scheduling and management platform built for growing brands, agencies, and multi-location businesses.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (tiered annual or monthly plans)$q$, pricing_model),
  starting_price = COALESCE($q$$24/month (Basic, billed annually at $290/year)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Melbourne, Victoria, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sked Social Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Sked Social is an Australian social media scheduling platform for brands and agencies. See 2026 pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sked Social is a social media scheduling and management platform founded in 2013 and headquartered in Melbourne, Victoria, Australia. The platform serves solo social media managers, marketing teams, and agencies that need to plan, approve, and publish content across multiple social channels, including Instagram, TikTok, Facebook, LinkedIn, Pinterest, YouTube, and Google Business Profile. Sked Social differentiates itself with agency-focused workflow features such as customizable client approval portals, white-label reporting, and unified social inbox messaging, alongside standard scheduling, content calendars, and analytics. As of recent public data, the company reports over $10 million in annual revenue and roughly 10,000 customers, while employing an estimated 11 to 50 people, with several public counts placing the team at around 20 to 26 staff spread across multiple continents. Pricing runs on four tiers: Basic at $24 per month, billed annually at $290 per year, for a single user and one profile per platform; Grow at $58 per month, billed annually at $690 per year, for 3 users and 6 profiles with optional approval workflow add-ons; Accelerate at $166 per month, billed annually at $1,990 per year, for 6 users and 10 profiles with approvals and advanced analytics included; and a Custom tier starting from $249 per month for enterprise-level access controls and dedicated account management. Every plan includes a 14-day free trial with no credit card required, brand-trained AI caption generation, ideas and draft management, and mobile apps for iOS and Android.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f4d365b4-e7ab-418b-af7c-34a65c4165e9';

