-- ── Sketch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sketch is a vector-based digital design tool for Mac used by UI/UX designers to create interfaces, prototypes, and design systems, made by Sketch B.V.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per-editor, annual or monthly) plus a one-time Mac-only license option$q$, pricing_model),
  starting_price = COALESCE($q$$12/month per editor (Standard, billed annually)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Approximately 100 employees$q$, company_size),
  headquarters = COALESCE($q$The Hague, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sketch Review 2026: Pricing, Features for UI/UX Design$q$, seo_title),
  seo_meta_description = COALESCE($q$Sketch is a Mac-based UI/UX design tool from Sketch B.V. See 2026 pricing plans, features, pros and cons for designers and teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sketch is a vector-based digital design application originally created in 2010 by Pieter Omvlee and a small team working under the name Bohemian Coding in the Netherlands; the product and company are now operated as Sketch B.V. Sketch was one of the first mainstream tools to shift UI and UX design away from Photoshop toward a purpose-built, vector-first workflow, and it helped popularize concepts like reusable symbols and shared design libraries that later spread across the design-tool category, including competitors like Figma and Adobe XD. The application remains a native macOS app, complemented by a browser-based web app and mobile companion apps for previewing designs on iPhone and iPad, plus real-time multiplayer collaboration, version history, and developer handoff tools for exporting specs and assets. Sketch is sold on a per-editor subscription: the Standard plan costs $12 per editor per month when billed annually and includes real-time collaboration, unlimited documents, and unlimited free viewers; Professional costs $24 per editor per month and adds single sign-on, project archiving, and permission groups; Enterprise costs $44 per editor per month and adds SCIM provisioning and bring-your-own-key encryption; and a custom-priced Private Cloud tier offers a fully private hosted environment. Sketch also still sells a one-time $120 Mac-only license, including one year of updates, for freelancers who want a native offline app without collaboration features. The company employs roughly 100 people.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1c10185e-f762-462e-9a99-b6b50263b7cf';

