  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$500-700 employees$q$, company_size),
  headquarters = COALESCE($q$New York, NY, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Skillshare Review 2026: Pricing, Classes and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Skillshare is an online learning platform with thousands of creative classes. See 2026 pricing, features, pros and cons for individuals and teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Skillshare is an online learning platform founded by Michael Karnjanaprakorn and Malcolm Ong in New York City in November 2010, with the site publicly launching in 2011; the company remains headquartered in New York and today employs an estimated 500 to 700 people. Skillshare's catalog spans more than 30,000 classes, concentrated in creative and entrepreneurial skills such as illustration, graphic design, photography, video editing, writing, marketing, and productivity, taught by working practitioners rather than accredited academic instructors. The platform operates on a community model: most classes are short, project-based video lessons, and students are encouraged to complete a hands-on class project and share it for peer feedback rather than sit exams. Access to the full catalog requires a Premium Membership, priced at $167.88 per year, equivalent to $13.99 per month when billed annually, or a higher month-to-month rate typically between $17.99 and $32; a limited selection of classes remains free without a subscription. New users generally receive a free trial period before billing begins. Skillshare for Teams extends premium access to organizations at $159 per user per year, billed annually only, aimed at companies that want to offer employees ongoing creative and professional-development learning. Skillshare competes with platforms like Coursera, Udemy, MasterClass, and LinkedIn Learning, differentiating itself through project-based classes and a community-oriented, creator-led catalog rather than certificate-driven professional courses.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f40d2d28-fdc6-4f97-93db-e7e3e49b3d87';

